
/**
 * Constructeur principal du SDK EasyPay.
 *
 * @param {Object} api_keys - Les clés d'authentification marchand
 * @param {string} api_keys.publishable_key  - Clé publique (JWT token)
 * @param {string} api_keys.correlation_id   - Identifiant de corrélation (CID)
 * @param {string} api_keys.mode             - Environnement : "sandbox" ou "v1"
 */
function EcomEasypay(api_keys) {

    // Stocke les clés API et l'objet commande en propriétés d'instance
    this.api_keys = api_keys;
    this.order = {};

    /**
     * Affiche un message d'erreur en haut de la page sous forme d'alerte rouge.
     * Le message d'erreur à afficher (peut contenir du HTML)
     */
    const showError = (message) => {
        const alertDiv = document.createElement("div");
        alertDiv.className = "alert alert-danger";
        alertDiv.setAttribute("role", "alert");
        alertDiv.innerHTML = "<b>Erreur !</b> " + message;
        // Insère l'alerte tout en haut du body
        document.body.insertBefore(alertDiv, document.body.firstChild);
    };

    /**
     * Valide les clés API fournies lors de l'instanciation.
     * Vérifie que :
     * L'objet api_keys existe
     * Seules les propriétés autorisées sont présentes
     * Chaque valeur est une chaîne de caractères non nulle
     * Le mode est bien "sandbox" ou "v1"
     * true si valide, false sinon
     */
    const validateApiKeys = () => {
        if (!this.api_keys) {
            showError("API Keys is not defined");
            return false;
        }

        // Liste des propriétés autorisées dans api_keys
        const allowedKeys = ["publishable_key", "correlation_id", "mode"];

        for (const key in this.api_keys) {

            // Vérifie qu'aucune propriété inconnue n'est passée
            if (!allowedKeys.includes(key)) {
                showError("Propriété <b>" + key + "</b> Inconnue.");
                return false;
            }

            // Vérifie que la valeur est une chaîne non nulle
            if (this.api_keys[key] === null || typeof this.api_keys[key] !== "string") {
                showError("Veuillez vérifier la valeur de <b>" + key + "</b> (doit être une chaîne de caractères).");
                return false;
            }

            // Vérifie que le mode est bien "sandbox" ou "v1"
            if (key === "mode" && !["sandbox", "v1"].includes(this.api_keys[key])) {
                showError("Le mode doit être 'sandbox' ou 'v1'.");
                return false;
            }
        }

        return true;
    };

    /**
     * Valide les données de commande (order) avant l'envoi à l'API.
     * Vérifie que :
     * L'objet order est défini
     *  Seules les propriétés autorisées sont présentes
     *  Chaque valeur est une chaîne de caractères non nulle
     *  Les URLs commencent par http(s)://
     *  La devise est USD, CDF ou EUR
     *
     * @returns {boolean} true si valide, false sinon
     */
    const validateOrder = () => {
        if (!this.order) {
            showError("L'objet order n'est pas défini.");
            return false;
        }

        // Liste des champs autorisés dans l'objet order
        const allowedKeys = [
            "order_ref", "customer_name", "customer_email",
            "description", "currency", "amount",
            "success_url", "error_url", "cancel_url", "language"
        ];

        for (const key in this.order) {

            // Vérifie qu'aucun champ inconnu n'est envoyé
            if (!allowedKeys.includes(key)) {
                showError("Propriété <b>" + key + "</b> Inconnue.");
                return false;
            }

            // Vérifie que la valeur est une chaîne non nulle
            if (this.order[key] === null || typeof this.order[key] !== "string") {
                showError("Veuillez vérifier la valeur de <b>" + key + "</b> (doit être une chaîne de caractères).");
                return false;
            }

            // Vérifie le format des URLs de redirection
            if (["success_url", "error_url", "cancel_url"].includes(key) && this.order[key].indexOf("http") !== 0) {
                showError("Le format de <b>" + key + "</b> doit commencer par http(s)://");
                return false;
            }

            // Vérifie que la devise est parmi les valeurs acceptées
            if (key === "currency" && !["USD", "CDF", "EUR"].includes(this.order[key])) {
                showError("La devise (currency) doit être USD, CDF ou EUR.");
                return false;
            }
        }

        return true;
    };

    /**
     * Initialise la transaction auprès de l'API EasyPay via une requête XHR POST.
     * En cas de succès (HTTP 200), redirige le client vers la page de paiement EasyPay.
     * En cas d'échec, affiche un message d'erreur.
     *
     * L'icône spinner à animer pendant le chargement
     */
    const initiatePayment = (spinner) => {

        // Construction de l'URL de l'API avec les credentials en query string
        const url = "https://www.e-com-easypay.com/"
            + this.api_keys.mode
            + "/payment/initialization?cid="
            + this.api_keys.correlation_id
            + "&token="
            + this.api_keys.publishable_key;

        // Ajout automatique des canaux de paiement acceptés (obligatoire par l'API)
        this.order.channels = [
            { channel: "CREDIT CARD" },
            { channel: "MOBILE MONEY" }
        ];

        // Active l'animation du spinner pendant la requête
        spinner.className = "fa fa-spinner fa-spin";

        // Création et configuration de la requête XHR
        const xhr = new XMLHttpRequest();
        xhr.open("POST", url, true); // true = requête asynchrone
        xhr.setRequestHeader("Content-Type", "application/json");

        /**
         * Callback appelé à chaque changement d'état de la requête XHR.
         * readyState === 4 signifie que la requête est terminée.
         */
        xhr.onreadystatechange = () => {
            if (xhr.readyState === 4) {

                // Arrête le spinner une fois la réponse reçue
                spinner.className = "";

                if (xhr.status === 200) {
                    // Succès : parse la réponse JSON et redirige vers la page de paiement
                    const response = JSON.parse(xhr.responseText);
                    console.log(response);

                    // Redirection vers la passerelle EasyPay avec la référence de transaction
                    window.location.href = "https://www.e-com-easypay.com/"
                        + this.api_keys.mode
                        + "/payment/initialization?reference="
                        + response.reference;
                } else {
                    // Erreur HTTP : affiche un message à l'utilisateur
                    showError("Une erreur est survenue lors de l'initialisation du paiement.");
                }
            }
        };

        // Envoi de la commande sérialisée en JSON dans le corps de la requête
        xhr.send(JSON.stringify(this.order));
    };

    /**
     * Crée et injecte le bouton "Payer avec EasyPay" dans le conteneur
     * HTML ayant l'id "ecom-easypay".
     * Charge également FontAwesome pour l'icône spinner.
     */
    const renderPayButton = () => {

        // Chargement dynamique de FontAwesome pour l'icône de chargement
        const head = document.getElementsByTagName("head")[0];
        const link = document.createElement("link");
        link.setAttribute("rel", "stylesheet");
        link.setAttribute("href", "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/4.7.0/css/font-awesome.min.css");
        head.appendChild(link);

        // Vérification de l'existence du conteneur obligatoire dans le DOM
        const container = document.getElementById("ecom-easypay");
        if (!container) {
            showError("Le conteneur id <b>ecom-easypay</b> est introuvable dans la page HTML.");
            return;
        }

        // Création du bouton et de son icône spinner
        const button = document.createElement("button");
        const spinner = document.createElement("i");

        button.innerHTML = "Payer avec EasyPay ";

        // Style inline du bouton (inspiré du style Apple Pay)
        button.style.cssText = "background-image: linear-gradient(#42A1EC, #0070C9); "
            + "border: 1px solid #0077CC; border-radius: 4px; color: #FFFFFF; "
            + "font-size: 17px; font-weight: 400; padding: 4px 15px; "
            + "cursor: pointer; text-align: center;";

        // Injection du bouton dans le conteneur, puis du spinner dans le bouton
        container.appendChild(button);
        button.appendChild(spinner);

        // Au clic sur le bouton, lance l'initialisation du paiement
        button.addEventListener("click", () => {
            initiatePayment(spinner);
        });
    };

    // ============================================================
    // Méthodes publiques — accessibles depuis votre code
    // ============================================================

    /**
     * Définit les données de commande sur l'instance.
     * Permet de passer l'order séparément avant d'appeler showPayButton().
     *
     *  Les données de la commande client
     *  L'objet order stocké
     */
    this.setOrder = (order) => {
        this.order = order;
        return this.order;
    };

    /**
     * Valide les clés API et les données de commande,
     * puis affiche le bouton "Payer avec EasyPay" si tout est valide.
     *
     * Peut être appelé de deux façons :
     *   1. easypay.showPayButton(order)      — passe l'order directement
     *   2. easypay.setOrder(order);           — ou séparément
     *      easypay.showPayButton();
     *
     *- (optionnel) Les données de la commande
     */
    this.showPayButton = (order = null) => {

        // Si l'order est passé directement en paramètre, on le stocke
        if (order !== null) {
            this.order = order;
        }

        // Lance la validation puis affiche le bouton si tout est correct
        if (validateApiKeys() && validateOrder()) {
            renderPayButton();
        }
    };
}